INSERT INTO `photo` VALUES (1,'山间日落',4,'<p>在山顶拍摄的绝美日落，云彩被染成了橙红色，美不胜收。</p>','https://s.panlai.com/upload/20240408020526171251312638855.jpg','https://s.panlai.com/upload/20240408020526171251312638855.jpg','2025-07-29 15:31:25','2026-01-17 07:35:00','学习'),(2,'海边漫步',4,'<p>沿着海岸线散步，享受海风拂面的感觉，远处的海浪不断涌来。</p>','https://s.panlai.com/zb_users/upload/2025/04/20250409201253174420077367508.jpg','https://s.panlai.com/zb_users/upload/2025/04/20250409201253174420077367508.jpg','2025-07-29 16:18:53','2025-07-30 16:57:05','学习'),(3,'城市夜景',4,'<p>城市的夜晚总是那么迷人，灯火辉煌，车水马龙。</p>','https://s.panlai.com/zb_users/upload/2025/04/20250430235516174602851628125.jpg','https://s.panlai.com/zb_users/upload/2025/04/20250430235516174602851628125.jpg','2025-07-29 16:49:46','2025-07-30 16:59:56','学习'),(4,'咖啡时光',5,'<p>周末的早晨，坐在咖啡馆里，享受一杯香浓的咖啡和一本好书。</p>','https://s.panlai.com/zb_users/upload/2025/03/20250330195448174333568880852.jpg','https://s.panlai.com/zb_users/upload/2025/03/20250330195448174333568880852.jpg','2025-07-29 17:05:09','2025-07-30 17:00:11','动漫'),(5,'美少女',5,'<p>春天到了，樱花盛开，万物复苏。</p>','https://s.panlai.com/zb_users/upload/2025/03/20250324151824174280070494713.jpg','https://s.panlai.com/zb_users/upload/2025/03/20250324151824174280070494713.jpg','2025-07-29 17:05:54','2025-07-30 17:02:07','动漫'),(6,'山间小屋',4,'<p>在深山里发现的一座小屋，仿佛与世隔绝，宁静而美好。</p>','https://s.panlai.com/zb_users/upload/2025/04/bizhihui_com_202504061743928261788631.jpg','https://s.panlai.com/zb_users/upload/2025/04/bizhihui_com_202504061743928261788631.jpg','2025-07-29 17:06:23','2025-07-30 17:02:21','学习'),(7,'老街巷',4,'<p>古老的街巷里，保留着传统的建筑和生活方式。</p>','https://s.panlai.com/zb_users/upload/2025/04/bizhihui_com_202504061743927021418643.jpg','https://s.panlai.com/zb_users/upload/2025/04/bizhihui_com_202504061743927021418643.jpg','2025-07-29 17:06:58','2025-07-30 17:02:32','学习'),(8,'晨曦',4,'<p>清晨的第一缕阳光洒在大地上，一切都显得那么清新和宁静。</p>','https://s.panlai.com/zb_users/upload/2025/03/20250331131655174339821562910.jpg','https://s.panlai.com/zb_users/upload/2025/03/20250331131655174339821562910.jpg','2025-07-29 17:07:30','2025-07-30 17:02:47','学习'),(9,'书店一角',5,'<p>最喜欢在书店的角落找一本好书，静静地阅读一个下午。</p>','https://s.panlai.com/zb_users/upload/2025/03/20250326041153174293351334361.png-arthumbs','https://s.panlai.com/zb_users/upload/2025/03/20250326041153174293351334361.png-arthumbs','2025-07-29 17:08:04','2025-07-29 17:08:04','动漫'),(10,'长发猫女',4,'<p> 长发 锁骨 坐着 室内 女性 猫女 痣 脚底 蓝眼睛 动漫 女孩 动物 耳朵 汗水 猫耳朵 猫尾巴 星星 城市 灯光 夜 天空 黑发 鞭子 4K壁纸</p><p><br></p>','https://s.panlai.com/zb_users/upload/2025/05/20250502053631174613539130176.png','https://s.panlai.com/zb_users/upload/2025/05/20250502053631174613539130176.png','2025-07-30 16:26:58','2025-07-30 17:02:55','学习'),(12,'可爱小女孩',5,'<p>可爱 小女孩 帽子 玩具熊 4k 壁纸 4K壁纸</p><p><br></p>','https://s.panlai.com/zb_users/upload/2025/03/bizhihui_com_202503311743399344551088.jpg','https://s.panlai.com/zb_users/upload/2025/03/bizhihui_com_202503311743399344551088.jpg','2025-07-30 16:31:27','2025-07-30 17:03:17','动漫'),(13,'枫叶女孩',5,'<p>枫叶 女孩 圆窗 4K 高清 壁纸 4K壁纸</p><p><br></p>','https://s.panlai.com/zb_users/upload/2025/03/bizhihui_com_202503311743398477613583.jpg','https://s.panlai.com/zb_users/upload/2025/03/bizhihui_com_202503311743398477613583.jpg','2025-07-30 16:33:27','2025-07-30 17:03:29','动漫'),(15,'卡通动漫',5,'<p>深色头发 脸部 蓝色头发 手到脸 深色眼睛 手 电脑壁纸 4K壁纸</p><p><br></p>','https://s.panlai.com/zb_users/upload/2026/01/bizhihui_com_202601191768810738814236.jpg','https://s.panlai.com/zb_users/upload/2026/01/bizhihui_com_202601191768810738814236.jpg','2026-01-19 12:57:05','2026-01-19 12:57:05','动漫');
/*!40000 ALTER TABLE `photo` ENABLE KEYS */;
